namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

<nav class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between mb-0 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCompleted = stepIndex < CurrentStep;
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn btn-link step-button p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block mt-1 text-success fw-semibold">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@(stepIndex + 1)</span>
                        <span class="step-label d-block mt-1 @(isCurrent ? "fw-semibold text-primary" : "text-muted")">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

<style>
    .step-indicator .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        border-radius: 50%;
        font-size: 0.9rem;
        font-weight: bold;
    }
    .step-indicator .step-button {
        border: none;
        background: none;
        cursor: pointer;
    }
    .step-indicator .step-label {
        font-size: 0.8rem;
    }
</style>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control" value="@FullName" @onchange="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control" value="@Email" @onchange="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control" value="@Phone" @onchange="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control" rows="2" @onchange="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
</div>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="OnNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public string ValidationError { get; set; } = "";
    [Parameter] public bool IsValidating { get; set; }

    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? "" })" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = ParseDate(e.Value) })" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = ParseNullableDate(e.Value) })" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3"
                          @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })">@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string ValidationError { get; set; } = "";
    [Parameter] public EventCallback<string> ValidationErrorChanged { get; set; }

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == default)
            {
                await ValidationErrorChanged.InvokeAsync("Each position requires a company name, job title, and start date.");
                return;
            }
        }
        await ValidationErrorChanged.InvokeAsync("");
        await OnNext.InvokeAsync();
    }

    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
    private DateTime ParseDate(object? value) => DateTime.TryParse(value?.ToString(), out var d) ? d : default;
    private DateTime? ParseNullableDate(object? value) => DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}

namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication;

public record WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @onchange="e => UpdateReference(index, reference with { Name = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @onchange="e => UpdateReference(index, reference with { Relationship = e.Value?.ToString() ?? "" })" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @onchange="e => UpdateReference(index, reference with { Email = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @onchange="e => UpdateReference(index, reference with { Phone = e.Value?.ToString() ?? "" })" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = [];
    [Parameter] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string ValidationError { get; set; } = "";
    [Parameter] public EventCallback<string> ValidationErrorChanged { get; set; }

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private async Task HandleNext()
    {
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                await ValidationErrorChanged.InvokeAsync("All reference fields are required.");
                return;
            }
        }
        await ValidationErrorChanged.InvokeAsync("");
        await OnNext.InvokeAsync();
    }
}

namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication;

public record ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxCharacters"
              value="@CoverLetter"
              @oninput="HandleInput">@CoverLetter</textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxCharacters characters
    </div>
</div>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxCharacters = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string ValidationError { get; set; } = "";
    [Parameter] public EventCallback<string> ValidationErrorChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > MaxCharacters)
            value = value[..MaxCharacters];
        await CoverLetterChanged.InvokeAsync(value);
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            await ValidationErrorChanged.InvokeAsync("Please enter a cover letter.");
            return;
        }
        await ValidationErrorChanged.InvokeAsync("");
        await OnNext.InvokeAsync();
    }
}

@namespace sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication

@if (IsSubmitted)
{
    <div class="text-center py-5">
        <div class="mb-3">
            <span class="display-1 text-success">✓</span>
        </div>
        <h3 class="text-success">Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@ApplicationId</strong></p>
        <p class="text-muted">Thank you for applying. We will review your application and get back to you.</p>
    </div>
}
else
{
    <h4 class="mb-3">Review & Submit</h4>

    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt>
                <dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <span class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
