@page "/apply"
@using sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Components.JobApplication
@using sv_18c4c51bd9b444c7aa3b3a6dcf657dea.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" StepNames="stepNames" OnStepClicked="GoToCompletedStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep
                FullName="@fullName" FullNameChanged="v => fullName = v"
                Email="@email" EmailChanged="v => email = v"
                Phone="@phone" PhoneChanged="v => phone = v"
                Address="@address" AddressChanged="v => address = v"
                ValidationError="@validationError"
                IsValidating="@isValidating"
                OnNext="HandlePersonalInfoNext" />
            break;

        case 1:
            <WorkHistoryStep
                Entries="workEntries" EntriesChanged="v => workEntries = v"
                ValidationError="@validationError" ValidationErrorChanged="v => validationError = v"
                OnBack="GoBack" OnNext="GoForward" />
            break;

        case 2:
            <ReferencesStep
                References="references" ReferencesChanged="v => references = v"
                ValidationError="@validationError" ValidationErrorChanged="v => validationError = v"
                OnBack="GoBack" OnNext="GoForward" />
            break;

        case 3:
            <CoverLetterStep
                CoverLetter="@coverLetter" CoverLetterChanged="v => coverLetter = v"
                ValidationError="@validationError" ValidationErrorChanged="v => validationError = v"
                OnBack="GoBack" OnNext="GoForward" />
            break;

        case 4:
            <ReviewStep
                FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                IsSubmitted="@isSubmitted" ApplicationId="@applicationId"
                IsSubmitting="@isSubmitting" SubmissionError="@submissionError"
                OnEditStep="GoToCompletedStep"
                OnBack="GoBack"
                OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    private static readonly List<string> stepNames =
    [
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    ];

    private int currentStep;
    private string validationError = "";
    private bool isValidating;

    // Step 1 state
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 state
    private List<WorkEntryModel> workEntries = [new()];

    // Step 3 state
    private List<ReferenceModel> references = [new(), new()];

    // Step 4 state
    private string coverLetter = "";

    // Step 5 state
    private bool isSubmitted;
    private int applicationId;
    private bool isSubmitting;
    private string submissionError = "";

    private async Task HandlePersonalInfoNext()
    {
        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email)
            || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        validationError = "";
        StateHasChanged();

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(email);
            if (!isValid)
            {
                validationError = "The email address is not valid.";
                return;
            }
            GoForward();
        }
        catch
        {
            validationError = "Failed to validate email. Please try again.";
        }
        finally
        {
            isValidating = false;
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submissionError = "";
        StateHasChanged();

        try
        {
            var workHistory = new WorkHistory(
                workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description
                )).ToList()
            );

            var refs = references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
            ).ToList();

            var personal = new PersonalInfo(fullName, email, phone, address);
            var application = new JobApplication(personal, workHistory, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch
        {
            submissionError = "Failed to submit application. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void GoForward()
    {
        validationError = "";
        currentStep++;
    }

    private void GoBack()
    {
        validationError = "";
        currentStep--;
    }

    private void GoToCompletedStep(int step)
    {
        if (step < currentStep)
        {
            validationError = "";
            currentStep = step;
        }
    }
}

